mapper.update:
UPDATE agent_conversation_summary
SET status = 'SUPERSEDED',
    updated_at = CURRENT_TIMESTAMP
WHERE task_id = #{taskId}
  AND user_id = #{userId}
  AND status = 'ACTIVE'

mapper.select:
SELECT *
FROM agent_conversation_summary
WHERE task_id = #{taskId}
ORDER BY updated_at DESC, id DESC
LIMIT #{limit}

SELECT COUNT(*)
FROM agent_conversation_summary
WHERE task_id = #{taskId}

SELECT *
FROM agent_conversation_summary
WHERE task_id = #{taskId}
  AND status = #{status}
ORDER BY updated_at DESC, id DESC
LIMIT #{limit}

SELECT *
FROM agent_conversation_summary
WHERE id = #{id}
  AND task_id = #{taskId}
